interrupt.pattern_request:
class ApprovalRequest(RequestInfoMessage):
    checkpoint: str = ''
    recommended: list = []

class HitlNode(Executor):
    @handler
    async def run(self, message: Payload, ctx: WorkflowContext) -> None:
        if message.run_mode == 'automated':
            await ctx.send_message(Approved(ids=message.recommended))
            return
        await ctx.send_message(
            ApprovalRequest(checkpoint='approve_removals', recommended=message.recommended),
            target_id=request_info.id,
        )

interrupt.pattern_resume:
class ApplyDecision(Executor):
    @handler
    async def run(self, reply: RequestResponse[ApprovalRequest, list], ctx: WorkflowContext) -> None:
        approved = reply.data if reply.data is not None else reply.original_request.recommended
        await ctx.send_message(Approved(ids=approved))

